patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index f072f5cec309..d25ffcb1cbcf 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1133,6 +1133,18 @@ Value *InstCombinerImpl::SimplifySelectsFeedingBinaryOp(BinaryOperator &I,

   if (LHSIsSelect && RHSIsSelect && A == D) {
     // (A ? B : C) op (A ? E : F) -> A ? (B op E) : (C op F)
+    // If the true/false values are swapped between the selects (B == F && C == E),
+    // then the result is B op C (or C op B) when the operation is commutative.
+    if (B == F && C == E && I.isCommutative()) {
+      Value *Res = simplifyBinOp(Opcode, B, C, FMF, Q);
+      if (!Res) {
+        Res = Builder.CreateBinOp(Opcode, B, C);
+        if (auto *BO = dyn_cast<BinaryOperator>(Res))
+          BO->copyIRFlags(&I);
+      }
+      Res->takeName(&I);
+      return Res;
+    }
     Cond = A;
     True = simplifyBinOp(Opcode, B, E, FMF, Q);
     False = simplifyBinOp(Opcode, C, F, FMF, Q);

